  className = "",
  ...props
}) {
  return (
    <button
      className={`vp-button vp-button-${variant} ${className}`.trim()}
      disabled={disabled}
      {...props}
    >
      {icon ? <Icon name={icon} size={16} /> : null}
      <span>{children}</span>
    </button>
  );
}
